function setLang(lang){
  if(!T[lang])lang="en";
  currentLang=lang;
  localStorage.setItem("besafe_website_lang",lang);
  document.documentElement.lang=lang;
  document.getElementById("lang-flag").textContent=LANGS[lang].flag;
  document.getElementById("lang-code").textContent=LANGS[lang].code;
  document.querySelectorAll(".lang-opt").forEach(el=>el.classList.toggle("active",el.dataset.lang===lang));
  document.querySelectorAll("[data-i18n]").forEach(el=>{
    const k=el.dataset.i18n;
    const v=(T[lang]&&T[lang][k])||T.en[k];
    if(v){
      if(el.tagName==="INPUT"||el.tagName==="TEXTAREA")el.placeholder=v;
      else el.innerHTML=v;
    }
  });
  document.querySelectorAll("[data-i18n-ph]").forEach(el=>{
    const k=el.dataset.i18nPh;
    const v=(T[lang]&&T[lang][k])||T.en[k];
    if(v)el.placeholder=v;
  });
  closeLangDropdown();
}
function toggleLangDropdown(){document.getElementById("lang-dropdown").classList.toggle("open")}
function closeLangDropdown(){document.getElementById("lang-dropdown").classList.remove("open")}
document.addEventListener("click",e=>{if(!e.target.closest(".lang-switch"))closeLangDropdown()});
document.addEventListener("DOMContentLoaded",()=>{if(currentLang!=="en")setLang(currentLang)});
